mapper.select:
SELECT e.*, ar.approver_name as lastApproverName, ar.comment_text as lastApproverOpinion FROM oa_expense e LEFT JOIN ( SELECT business_key, approver_name, comment_text FROM oa_approval_record WHERE action_type = 'approve' ORDER BY create_time DESC ) ar ON CONCAT('expense:', e.expense_id) = ar.business_key WHERE e.approval_status IN ('approved', 'rejected')
AND e.dept_id = #{deptId}
ORDER BY e.create_time DESC LIMIT #{limit}
